<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller;use App\Models\Slider;use Illuminate\Http\{RedirectResponse,Request};use Illuminate\View\View;
class SliderController extends Controller{public function index():View{return view('admin.sliders.index',['sliders'=>Slider::orderBy('sort_order')->paginate(15)]);}public function create():View{return view('admin.sliders.form',['slider'=>new Slider()]);}public function store(Request $r):RedirectResponse{Slider::create($this->data($r));return redirect()->route('admin.sliders.index');}public function edit(Slider $slider):View{return view('admin.sliders.form',compact('slider'));}public function update(Request $r,Slider $slider):RedirectResponse{$slider->update($this->data($r));return redirect()->route('admin.sliders.index');}public function destroy(Slider $slider):RedirectResponse{$slider->delete();return back();}private function data(Request $r):array{return $r->validate(['title'=>'required','subtitle'=>'nullable','image'=>'nullable','button_text'=>'nullable','button_link'=>'nullable','sort_order'=>'nullable|integer','is_active'=>'nullable|boolean'])+['is_active'=>$r->boolean('is_active',true)];}}
